// Frogger Player Behavior Script
// Manages movement, collision detection, and game state

// Game constants
const GRID_SIZE = 40;
const SCREEN_WIDTH = 800;
const SCREEN_HEIGHT = 600;
const SPAWN_X = 400;
const SPAWN_Y = 550;

// Road/Obstacle Y positions
const CAR_LANES = [500, 430, 360];
const COLLISION_RADIUS = 60;
const WATER_TOP = 240;
const WATER_BOTTOM = 300;
const LOG_LANES = [240, 300];
const GOAL_Y = 50;

// Game state enum
const GameState = {
  PLAYING: "playing",
  WON: "won",
  LOST: "lost"
};

// Car data: {y, speed_px_per_frame, moving_right}
const CAR_CONFIG = [
  { y: 500, speed: 2, movingRight: true },
  { y: 430, speed: 2.5, movingRight: false },
  { y: 360, speed: 3, movingRight: true }
];

// Log data: {y, speed_px_per_frame, moving_right}
const LOG_CONFIG = [
  { y: 240, speed: 2, movingRight: false },
  { y: 300, speed: 3, movingRight: true }
];

// Game state variables
let gameState = GameState.PLAYING;
let frogs = {}; // Will store frog position data
let framesSinceOnLog = 0; // Counter for water drowning mechanic
let lastInputFrame = -1; // Prevent multiple moves per frame

export function onStart(entity) {
  // Initialize frog state
  entity.transform.x = SPAWN_X;
  entity.transform.y = SPAWN_Y;

  // Store frog state tracking
  frogs = {
    x: SPAWN_X,
    y: SPAWN_Y,
    onLog: false,
    inWater: false,
    drowning: false
  };

  framesSinceOnLog = 0;
  console.log(`Frogger started at (${SPAWN_X}, ${SPAWN_Y})`);
}

export function onUpdate(entity, dt) {
  if (gameState !== GameState.PLAYING) {
    return; // Game is not active
  }

  // Handle player input
  handleInput(entity);

  // Update water and log mechanics
  updateWaterAndLogMechanics(entity);

  // Check car collisions
  checkCarCollisions(entity);

  // Check goal condition
  checkGoal(entity);

  // Check if out of bounds (side edges have wrapping for vehicles)
  clampFrogPosition(entity);
}

/**
 * Handle arrow key input for frog movement
 */
function handleInput(entity) {
  // Check for arrow key presses (we'll use a simple input system)
  // This assumes the engine provides input detection

  // Arrow keys: UP, DOWN, LEFT, RIGHT
  // Each key moves frog in 40px grid increments

  const inputMap = {
    'ArrowUp': { x: 0, y: -GRID_SIZE },
    'ArrowDown': { x: 0, y: GRID_SIZE },
    'ArrowLeft': { x: -GRID_SIZE, y: 0 },
    'ArrowRight': { x: GRID_SIZE, y: 0 }
  };

  // Check all possible inputs (would be integrated with engine's input system)
  // For now, we'll simulate input checking
  for (const [key, movement] of Object.entries(inputMap)) {
    if (isKeyPressed(key)) {
      const newX = frogs.x + movement.x;
      const newY = frogs.y + movement.y;

      // Only move if within bounds
      if (newX >= 0 && newX < SCREEN_WIDTH && 
          newY >= 0 && newY < SCREEN_HEIGHT) {
        frogs.x = newX;
        frogs.y = newY;
        entity.transform.x = frogs.x;
        entity.transform.y = frogs.y;
      }

      break; // Only one input per frame
    }
  }
}

/**
 * Check if a key is currently pressed
 * Note: This requires engine input integration
 */
function isKeyPressed(key) {
  // This would be replaced with actual engine input
  // Placeholder for key detection
  return false;
}

/**
 * Handle water mechanics and log carrying
 */
function updateWaterAndLogMechanics(entity) {
  const inWaterZone = frogs.y >= WATER_TOP && frogs.y <= WATER_BOTTOM;

  if (inWaterZone) {
    // Check if on a log
    frogs.inWater = true;
    frogs.onLog = isOnLog(frogs.x, frogs.y);

    if (frogs.onLog) {
      // Move with log
      const logData = getLogAtY(frogs.y);
      if (logData) {
        const movement = logData.movingRight ? logData.speed : -logData.speed;
        frogs.x += movement;

        // Wrap around screen edges
        if (frogs.x < 0) frogs.x += SCREEN_WIDTH;
        if (frogs.x >= SCREEN_WIDTH) frogs.x -= SCREEN_WIDTH;
      }
      framesSinceOnLog = 0;
    } else {
      // Not on log - count frames until drowning
      framesSinceOnLog++;
      if (framesSinceOnLog > 5) {
        // Frog drowns
        respawnFrog(entity);
        return;
      }
    }
  } else {
    // Not in water
    frogs.inWater = false;
    frogs.onLog = false;
    framesSinceOnLog = 0;
  }

  entity.transform.x = frogs.x;
  entity.transform.y = frogs.y;
}

/**
 * Check if frog is on a log at given position
 */
function isOnLog(x, y) {
  for (const logData of LOG_CONFIG) {
    if (Math.abs(y - logData.y) < GRID_SIZE) {
      // Simple collision check - frog must be roughly on log
      return true;
    }
  }
  return false;
}

/**
 * Get log configuration at given Y position
 */
function getLogAtY(y) {
  for (const logData of LOG_CONFIG) {
    if (Math.abs(y - logData.y) < GRID_SIZE) {
      return logData;
    }
  }
  return null;
}

/**
 * Check collisions with cars
 */
function checkCarCollisions(entity) {
  for (const carLane of CAR_LANES) {
    // Check if frog is in this car lane (Y-axis)
    if (Math.abs(frogs.y - carLane) < COLLISION_RADIUS / 2) {
      // Simple collision detection: check horizontal distance
      // In a real game, we'd check against actual car positions
      // For now, we'll use a probabilistic model or check against virtual cars

      if (checkCarCollisionAtLane(frogs.x, carLane)) {
        respawnFrog(entity);
        return;
      }
    }
  }
}

/**
 * Check if frog collides with a car at given lane
 * This simulates moving cars
 */
function checkCarCollisionAtLane(frogX, carLaneY) {
  const carConfig = CAR_CONFIG.find(c => c.y === carLaneY);
  if (!carConfig) return false;

  // Simulate car positions - cars spawn off screen and move across
  // For each car lane, calculate virtual car positions
  // A simple approach: divide screen into car-width sections
  const carWidth = 50;
  const carSpacing = 150;
  const numCars = Math.ceil((SCREEN_WIDTH + carSpacing) / carSpacing);

  for (let i = 0; i < numCars; i++) {
    let carX = (i * carSpacing);

    // Apply movement based on direction
    if (carConfig.movingRight) {
      carX = (carX + (Math.random() * SCREEN_WIDTH)) % SCREEN_WIDTH;
    } else {
      carX = (carX - (Math.random() * SCREEN_WIDTH)) % SCREEN_WIDTH;
      if (carX < 0) carX += SCREEN_WIDTH;
    }

    // Check collision with frog
    if (Math.abs(frogX - carX) < COLLISION_RADIUS) {
      return true;
    }
  }

  return false;
}

/**
 * Check if frog reached the goal
 */
function checkGoal(entity) {
  if (frogs.y <= GOAL_Y) {
    gameState = GameState.WON;
    console.log("🎉 YOU WIN! Frog reached the goal!");
    // Could trigger level reset or show UI here
  }
}

/**
 * Clamp frog position within screen bounds
 */
function clampFrogPosition(entity) {
  frogs.x = Math.max(0, Math.min(frogs.x, SCREEN_WIDTH - 1));
  frogs.y = Math.max(0, Math.min(frogs.y, SCREEN_HEIGHT - 1));
}

/**
 * Respawn frog at starting position
 */
function respawnFrog(entity) {
  frogs.x = SPAWN_X;
  frogs.y = SPAWN_Y;
  frogs.onLog = false;
  frogs.inWater = false;
  framesSinceOnLog = 0;
  entity.transform.x = SPAWN_X;
  entity.transform.y = SPAWN_Y;
  console.log("💀 Frog died! Respawned at starting position.");
}

/**
 * Reset game state
 */
export function resetGame() {
  gameState = GameState.PLAYING;
  framesSinceOnLog = 0;
  console.log("Game reset!");
}

/**
 * Get current game state (for UI display)
 */
export function getGameState() {
  return {
    state: gameState,
    frogX: frogs.x,
    frogY: frogs.y,
    onLog: frogs.onLog,
    inWater: frogs.inWater
  };
}

